async def amain() -> None:
    engine = build_engine()
    factory = build_session_factory(engine)
    updated = 0
    try:
        async with factory() as session:
            for name, data in PROFILES.items():
                r = await session.execute(text(
                    "SELECT id FROM service_profile WHERE country='gb' AND name=:n"
                ), {"n": name})
                pid = r.scalar()
                if not pid:
                    print(f"  ⚠ {name} not found")
                    continue

                # Update profile.key_descriptions
                await session.execute(text(
                    "UPDATE service_profile SET key_descriptions = CAST(:k AS jsonb) WHERE id = :p"
                ), {"k": json.dumps(data["key_descriptions"]), "p": pid})

                # Update or insert UK translation
                uk = data["uk"]
                await session.execute(text(
                    "DELETE FROM service_profile_translation WHERE profile_id = :p AND language='uk'"
                ), {"p": pid})
                await session.execute(text("""
                    INSERT INTO service_profile_translation
                      (id, profile_id, language, short_description,
                       addresses_problems, target_audience, benefits, keywords,
                       sales_pitch, cross_sell, procedure_steps, contraindications,
                       aftercare_advice, created_at, updated_at)
                    VALUES
                      (gen_random_uuid(), :p, 'uk', :sd,
                       CAST(:ap AS jsonb), CAST(:ta AS jsonb), CAST(:bn AS jsonb), CAST(:kw AS jsonb),
                       :sp, CAST(:cs AS jsonb), CAST(:ps AS jsonb), CAST(:ci AS jsonb),
                       :aa, NOW(), NOW())
                """), {
                    "p": pid,
                    "sd": uk["short_description"],
                    "ap": json.dumps(uk["addresses_problems"]),
                    "ta": json.dumps(uk["target_audience"]),
                    "bn": json.dumps(uk["benefits"]),
                    "kw": json.dumps(uk["keywords"]),
                    "sp": uk["sales_pitch"],
                    "cs": json.dumps(uk["cross_sell"]),
                    "ps": json.dumps(uk["procedure_steps"]),
                    "ci": json.dumps(uk["contraindications"]),
                    "aa": uk["aftercare_advice"],
                })
                updated += 1
                print(f"  ↻ {name}")

            await session.commit()
            print(f"\nDONE: {updated} GB profiles updated")
    finally:
        await engine.dispose()


if __name__ == "__main__":
    asyncio.run(amain())
